    private CustomWebApplicationFactory _factory = null!;
    private HttpClient _client = null!;

    private static readonly JsonSerializerOptions JsonOpts = new() { PropertyNameCaseInsensitive = true };

    [SetUp]
    public void SetUp()
    {
        _factory = new CustomWebApplicationFactory();
        _client = _factory.CreateClient();
    }

    [TearDown]
    public void TearDown()
    {
        _client.Dispose();
        _factory.Dispose();
    }

    private async Task<int> CreateProductAsync(string code, decimal price = 10m)
    {
        var resp = await _client.PostAsJsonAsync("/api/products",
            new ProductCreateUpdateDto { ProductCode = code, ProductName = $"Product {code}", UnitPrice = price });
        resp.EnsureSuccessStatusCode();
        var body = await resp.Content.ReadFromJsonAsync<JsonElement>(JsonOpts);
        return body.GetProperty("id").GetInt32();
    }

    private async Task<int> CreateOrderAsync(int? customerId = null)
    {
        var resp = await _client.PostAsJsonAsync("/api/orders",
            new OrderCreateDto { CustomerId = customerId, OrderDate = DateTime.UtcNow, Status = "New" });
        resp.EnsureSuccessStatusCode();
        var body = await resp.Content.ReadFromJsonAsync<JsonElement>(JsonOpts);
        return body.GetProperty("id").GetInt32();
    }

    [Test]
    public async Task GetSalesYtd_ReturnsOk()
    {
        var response = await _client.GetAsync("/api/reports/sales-ytd");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.OK));

        var dto = await response.Content.ReadFromJsonAsync<SalesYtdDto>(JsonOpts);
        Assert.That(dto, Is.Not.Null);
        Assert.That(dto!.Year, Is.EqualTo(DateTime.UtcNow.Year));
        Assert.That(dto.TotalSales, Is.GreaterThanOrEqualTo(0));
    }

