    [Test]
    public async Task GetInvoice_ReturnsInvoiceData()
    {
        var productId = await CreateProductAsync("INV-001", 20m);
        var orderId = await CreateOrderAsync();

        await _client.PostAsJsonAsync($"/api/orders/{orderId}/details",
            new OrderDetailCreateUpdateDto { ProductId = productId, Quantity = 2, UnitPrice = 20m });

        var response = await _client.GetAsync($"/api/reports/invoice/{orderId}");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.OK));

        var invoice = await response.Content.ReadFromJsonAsync<InvoiceDto>(JsonOpts);
        Assert.That(invoice, Is.Not.Null);
        Assert.That(invoice!.OrderId, Is.EqualTo(orderId));
        Assert.That(invoice.Subtotal, Is.EqualTo(40m));
        Assert.That(invoice.TaxRate, Is.EqualTo(0.085m));
        Assert.That(invoice.TaxAmount, Is.EqualTo(Math.Round(40m * 0.085m, 2)));
        Assert.That(invoice.Total, Is.EqualTo(invoice.Subtotal + invoice.TaxAmount));
    }

