        var productId = await CreateProductAsync("YTD-001", 100m);
        var orderId = await CreateOrderAsync();

        await _client.PostAsJsonAsync($"/api/orders/{orderId}/details",
            new OrderDetailCreateUpdateDto { ProductId = productId, Quantity = 3, UnitPrice = 100m });

        var response = await _client.GetAsync("/api/reports/sales-ytd");
        var dto = await response.Content.ReadFromJsonAsync<SalesYtdDto>(JsonOpts);
        Assert.That(dto!.TotalSales, Is.GreaterThanOrEqualTo(300m));
